// Stats from earlier step; anomaly list = this node's input (Get Critical Anomalies output).
const stats = $('Get Dashboard Stats').first().json;
const anomalyData = $input.first().json;

const totalFlows = stats.total_flows || 0;
const totalAnomalies = stats.total_anomalies || 0;
const anomalyRate = totalFlows > 0 ? (totalAnomalies / totalFlows) * 100 : 0;
const avgRiskScore = stats.avg_risk_score || 0;

// Thresholds (configurable via env vars)
const ANOMALY_RATE_THRESHOLD = 15;
const RISK_SCORE_THRESHOLD = 0.6;
const CRITICAL_COUNT_THRESHOLD = 5;

const riskDist = stats.risk_distribution || {};
const criticalCount = riskDist.Critical || 0;
const highCount = riskDist.High || 0;

const criticalAnomalies = anomalyData.threats || [];

const alerts = [];

if (anomalyRate > ANOMALY_RATE_THRESHOLD) {
  alerts.push({
    type: 'HIGH_ANOMALY_RATE',
    severity: 'Critical',
    message: `Anomaly rate ${anomalyRate.toFixed(1)}% exceeds threshold ${ANOMALY_RATE_THRESHOLD}%`,
    value: anomalyRate
  });
}

if (avgRiskScore > RISK_SCORE_THRESHOLD) {
  alerts.push({
    type: 'HIGH_AVG_RISK',
    severity: 'High',
    message: `Average risk score ${avgRiskScore.toFixed(3)} exceeds threshold ${RISK_SCORE_THRESHOLD}`,
    value: avgRiskScore
  });
}

if (criticalCount > CRITICAL_COUNT_THRESHOLD) {
  alerts.push({
    type: 'CRITICAL_THREATS',
    severity: 'Critical',
    message: `${criticalCount} critical threats detected (threshold: ${CRITICAL_COUNT_THRESHOLD})`,
    value: criticalCount
  });
}

return [{
  json: {
    timestamp: new Date().toISOString(),
    total_flows: totalFlows,
    total_anomalies: totalAnomalies,
    anomaly_rate: anomalyRate,
    avg_risk_score: avgRiskScore,
    risk_distribution: riskDist,
    attack_distribution: stats.attack_distribution || {},
    critical_count: criticalCount,
    high_count: highCount,
    has_alerts: alerts.length > 0,
    alert_count: alerts.length,
    alerts: alerts,
    top_critical_anomalies: criticalAnomalies.slice(0, 10),
    top_source_ips: stats.top_src_ips || [],
    top_dest_ips: stats.top_dst_ips || []
  }
}];

const data = $input.first().json;
const alerts = data.alerts || [];

let subject = `⚠️ NetGuard Alert: ${alerts.length} security issue(s) detected`;

let body = `# NetGuard Security Alert\n\n`;
body += `**Timestamp:** ${data.timestamp}\n\n`;
body += `## Summary\n`;
body += `- Total Flows Analyzed: **${data.total_flows}**\n`;
body += `- Anomalies Detected: **${data.total_anomalies}**\n`;
body += `- Anomaly Rate: **${data.anomaly_rate.toFixed(1)}%**\n`;
body += `- Avg Risk Score: **${data.avg_risk_score.toFixed(3)}**\n\n`;

body += `## Risk Distribution\n`;
const rd = data.risk_distribution;
body += `| Level | Count |\n|-------|-------|\n`;
for (const [level, count] of Object.entries(rd)) {
  body += `| ${level} | ${count} |\n`;
}
body += `\n`;

body += `## Alerts\n`;
for (const alert of alerts) {
  body += `### [${alert.severity}] ${alert.type}\n`;
  body += `${alert.message}\n\n`;
}

if (data.top_critical_anomalies && data.top_critical_anomalies.length > 0) {
  body += `## Top Critical Threats\n`;
  body += `| Source IP | Classification | Risk Score | Risk Level |\n`;
  body += `|-----------|---------------|------------|------------|\n`;
  for (const t of data.top_critical_anomalies.slice(0, 10)) {
    body += `| ${t.src_ip || 'N/A'} | ${t.classification || 'Unknown'} | ${(t.risk_score || 0).toFixed(3)} | ${t.risk_level || 'Unknown'} |\n`;
  }
}

if (data.top_source_ips && data.top_source_ips.length > 0) {
  body += `\n## Top Source IPs\n`;
  for (const ip of data.top_source_ips.slice(0, 5)) {
    body += `- **${ip.ip}**: ${ip.count} flows\n`;
  }
}

return [{ json: { subject, body, alert_count: alerts.length, severity: alerts[0]?.severity || 'Medium', raw_data: data } }];

// API is down — format a critical alert
const healthResponse = $('Health Check').first();

return [{
  json: {
    subject: '🚨 NetGuard API is DOWN',
    body: `# CRITICAL: NetGuard API Unreachable\n\n**Timestamp:** ${new Date().toISOString()}\n\nThe NetGuard backend API health check failed. The system may be offline.\n\n**Action Required:** Check if the FastAPI backend is running at the configured URL.\n\n**Response:** ${JSON.stringify(healthResponse?.json || 'No response', null, 2)}`,
    severity: 'Critical',
    alert_count: 1
  }
}];
